module up_down_counter(obf_CLK, RST, UP, DOWN, COUNT);
input obf_CLK, RST, UP, DOWN;
output [3:0] COUNT;
reg [3:0] COUNT;

always @(posedge obf_CLK or posedge RST) begin
    if (RST)
        COUNT <= 0;
    else if (UP)
        COUNT <= COUNT + 1;
    else if (DOWN)
        COUNT <= COUNT - 1;
end

endmodule
